gnN(){return"\ud83d\ude2d \u041e \u043d\u0435, \u0448\u0442\u043e\u0441\u044c\u0446\u0456 \u043f\u0430\u0439\u0448\u043b\u043e \u043d\u0435 \u0442\u0430\u043a. \u041a\u0430\u043b\u0456 \u0436\u0430\u0434\u0430\u0435\u0446\u0435, \u043c\u043e\u0436\u0430\u0446\u0435 \u043f\u0430\u0434\u0430\u0446\u044c \u0441\u043f\u0440\u0430\u0432\u0430\u0437\u0434\u0430\u0447\u0443 \u0430\u0431 \u043f\u0430\u043c\u044b\u043b\u043a\u0435 \u0440\u0430\u0441\u043f\u0440\u0430\u0443\u043e\u045e\u0448\u0447\u044b\u043a\u0430\u043c."},
