oF(d){return"\u041d\u044f\u0432\u0435\u0440\u043d\u044b \u043f\u0456\u043d-\u043a\u043e\u0434! \u041f\u0430\u0441\u043f\u0440\u0430\u0431\u0443\u0439\u0446\u0435 \u043f\u0440\u0430\u0437 "+d+" \u0441\u0435\u043a\u0443\u043d\u0434..."},
gnw(){return"\u041a\u0430\u043b\u0456 \u043b\u0430\u0441\u043a\u0430, \u0443\u0432\u044f\u0434\u0437\u0456\u0446\u0435 \u043b\u0456\u0447\u0431\u0443 \u0431\u043e\u043b\u044c\u0448\u0443\u044e \u0437\u0430 0"},
gf3(){return"\u0427\u0430\u0442 \u043f\u0435\u0440\u0430\u043c\u044f\u0441\u0446\u0456\u0446\u0446\u0430 \u045e \u0430\u0440\u0445\u0456\u045e. \u0406\u043d\u0448\u044b\u044f \u043a\u0430\u0440\u044b\u0441\u0442\u0430\u043b\u044c\u043d\u0456\u043a\u0456 \u0431\u0443\u0434\u0443\u0446\u044c \u0431\u0430\u0447\u044b\u0446\u044c \u0433\u044d\u0442\u0430 \u0442\u0430\u043a, \u0431\u044b\u0446\u0446\u0430\u043c \u0432\u044b \u0432\u044b\u0439\u0448\u043b\u0456 \u0437 \u0447\u0430\u0442\u0443."},
gnS(){return"\u0427\u0430\u0442 \u0431\u0443\u0434\u0437\u0435 \u043f\u0435\u0440\u0430\u0441\u0442\u0432\u043e\u0440\u0430\u043d\u044b \u0437 \u043d\u043e\u0432\u0430\u0439 \u0432\u0435\u0440\u0441\u0456\u044f\u0439 \u043f\u0430\u043a\u043e\u044e. \u0423\u0441\u0435 \u045e\u0434\u0437\u0435\u043b\u044c\u043d\u0456\u043a\u0456 \u0431\u0443\u0434\u0443\u0446\u044c \u043f\u0430\u0432\u0435\u0434\u0430\u043c\u043b\u0435\u043d\u044b \u043f\u0440\u0430 \u043d\u0435\u0430\u0431\u0445\u043e\u0434\u043d\u0430\u0441\u0446\u044c \u043f\u0435\u0440\u0430\u0439\u0441\u0446\u0456 \u045e \u043d\u043e\u0432\u044b \u0447\u0430\u0442. \u0412\u044b \u043c\u043e\u0436\u0430\u0446\u0435 \u0434\u0430\u0432\u0435\u0434\u0430\u0446\u0446\u0430 \u043f\u0440\u0430 \u0432\u0435\u0440\u0441\u0456\u0456 \u043f\u0430\u043a\u043e\u044f\u045e \u0442\u0443\u0442: https://spec.matrix.org/latest/rooms/"},
gnJ(){return"\u0412\u044b \u0432\u044b\u0439\u0434\u0437\u0435\u0446\u0435 \u0437 \u0433\u044d\u0442\u0430\u0439 \u043f\u0440\u044b\u043b\u0430\u0434\u044b \u0456 \u0431\u043e\u043b\u044c\u0448 \u043d\u0435 \u0431\u0443\u0434\u0437\u0435\u0446\u0435 \u0430\u0442\u0440\u044b\u043c\u043b\u0456\u0432\u0430\u0446\u044c \u043f\u0430\u0432\u0435\u0434\u0430\u043c\u043b\u0435\u043d\u043d\u0456."},
